        startHeight = buttonTransform.localPosition.y;
    }

    private void EndPress(HoverExitEventArgs eventArgs)
    {
        hoverInteractor = null;
        hoverHeight = 0.0f;
        startHeight = 0.0f;
        ApplyHeight(yMax);
    }

    private void Start()
    {
        SetMinMax();
    }

